import React, { useEffect, useState } from 'react';
import { jobService } from '../../services/api';

const APP_STATUS = {
  APPLIED:             { label: 'Applied',             cls: 'badge-applied' },
  APTITUDE_SCHEDULED:  { label: 'Aptitude Scheduled',  cls: 'badge-review' },
  APTITUDE_CLEARED:    { label: 'Aptitude Cleared',    cls: 'badge-approved' },
  APTITUDE_FAILED:     { label: 'Aptitude Failed',     cls: 'badge-rejected' },
  INTERVIEW_SCHEDULED: { label: 'Interview Scheduled', cls: 'badge-shortlisted' },
  SELECTED:            { label: '🎉 Selected!',        cls: 'badge-selected' },
  REJECTED:            { label: 'Not Selected',        cls: 'badge-rejected' },
};

export default function StudentApplications() {
  const [apps, setApps] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selected, setSelected] = useState(null);
  const [roundsData, setRoundsData] = useState(null);
  const [loadingRounds, setLoadingRounds] = useState(false);

  useEffect(() => {
    jobService.getMyApplications()
      .then(r => setApps(r.data))
      .catch(() => {})
      .finally(() => setLoading(false));
  }, []);

  const handleSelectApplication = async (app) => {
    if (selected?.id === app.id) {
      setSelected(null);
      setRoundsData(null);
      return;
    }
    setSelected(app);
    setLoadingRounds(true);
    try {
      const response = await jobService.getRoundScheduling(app.id);
      setRoundsData(response.data);
    } catch (err) {
      console.error('Failed to load rounds:', err);
    } finally {
      setLoadingRounds(false);
    }
  };

  return (
    <>
      <div className="topbar">
        <div>
          <div className="topbar-title">My Applications</div>
          <div className="topbar-sub">Track your job applications and interview status</div>
        </div>
        <span style={{ fontSize: 13, color: 'var(--gray-400)' }}>{apps.length} application{apps.length !== 1 ? 's' : ''}</span>
      </div>
      <div className="page-content">
        {loading && <div className="spinner-wrap"><div className="spinner" /></div>}
        {!loading && apps.length === 0 && (
          <div className="card" style={{ textAlign: 'center', color: 'var(--gray-400)', padding: 40 }}>
            No applications yet. Browse jobs and start applying!
          </div>
        )}

        <div style={{ display: 'grid', gridTemplateColumns: selected ? '1fr 360px' : '1fr', gap: 20, alignItems: 'start' }}>
          <div>
            {apps.map(app => {
              const sc = APP_STATUS[app.status] || { label: app.status, cls: 'badge-pending' };
              return (
                <div
                  key={app.id}
                  className="job-card"
                  onClick={() => handleSelectApplication(app)}
                  style={{ cursor: 'pointer', border: selected?.id === app.id ? '2px solid var(--navy)' : '1px solid var(--gray-100)' }}
                >
                  <div className="job-card-header">
                    <div>
                      <div className="job-card-title">{app.jobTitle}</div>
                      <div className="job-card-company">🏢 {app.companyName}</div>
                    </div>
                    <span className={`badge ${sc.cls}`}>{sc.label}</span>
                  </div>
                  <div style={{ fontSize: 12, color: 'var(--gray-400)', marginTop: 8 }}>
                    Applied: {new Date(app.appliedAt).toLocaleDateString('en-IN', { day: 'numeric', month: 'long', year: 'numeric' })}
                  </div>
                  {app.interviewDate && (
                    <div style={{ fontSize: 13, color: 'var(--navy)', marginTop: 6, fontWeight: 500 }}>
                      📅 Interview: {app.interviewDate} at {app.interviewTime} ({app.interviewMode})
                    </div>
                  )}
                  {app.status === 'SELECTED' && (
                    <div className="alert alert-success" style={{ marginTop: 10, marginBottom: 0 }}>
                      🎉 Congratulations! You have been selected for this position.
                    </div>
                  )}
                  {app.status === 'APTITUDE_SCHEDULED' && (
                    <div className="alert alert-warning" style={{ marginTop: 10, marginBottom: 0 }}>
                      <svg viewBox="0 0 24 24" fill="currentColor"><path d="M12 2C6.48 2 2 6.48 2 12s4.48 10 10 10 10-4.48 10-10S17.52 2 12 2zm1 15h-2v-6h2v6zm0-8h-2V7h2v2z"/></svg>
                      Aptitude test scheduled. Please check your email for details.
                    </div>
                  )}
                </div>
              );
            })}
          </div>

          {selected && (
            <div className="card" style={{ position: 'sticky', top: 80 }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 18 }}>
                <div>
                  <div style={{ fontWeight: 700, fontSize: 15, color: 'var(--navy)' }}>{selected.jobTitle}</div>
                  <div style={{ fontSize: 13, color: 'var(--gray-400)' }}>{selected.companyName}</div>
                </div>
                <button onClick={() => { setSelected(null); setRoundsData(null); }} style={{ background: 'none', border: 'none', cursor: 'pointer', color: 'var(--gray-400)', fontSize: 18 }}>✕</button>
              </div>

              {/* Application Details */}
              <div style={{ display: 'flex', flexDirection: 'column', gap: 10, fontSize: 13, marginBottom: 20, paddingBottom: 20, borderBottom: '1px solid var(--gray-100)' }}>
                {[
                  ['Status', <span className={`badge ${(APP_STATUS[selected.status] || {}).cls || ''}`}>{(APP_STATUS[selected.status] || {}).label || selected.status}</span>],
                  ['Applied', new Date(selected.appliedAt).toLocaleDateString('en-IN', { day: 'numeric', month: 'long', year: 'numeric' })],
                  selected.aptitudeScore != null && ['Aptitude Score', `${selected.aptitudeScore} — ${selected.aptitudeCleared ? '✅ Cleared' : '❌ Failed'}`],
                  selected.interviewDate && ['Interview Date', selected.interviewDate],
                  selected.interviewTime && ['Interview Time', selected.interviewTime],
                  selected.interviewMode && ['Interview Mode', selected.interviewMode],
                  selected.interviewResult && ['Interview Result', selected.interviewResult],
                  selected.interviewNotes && ['Notes', selected.interviewNotes],
                  selected.finalSelected != null && ['Final Decision', selected.finalSelected ? '✅ Selected' : '❌ Not selected'],
                ].filter(Boolean).map(([k, v]) => (
                  <div key={k} style={{ display: 'flex', gap: 8, borderBottom: '1px solid var(--gray-100)', paddingBottom: 10 }}>
                    <span style={{ color: 'var(--gray-400)', minWidth: 110, flexShrink: 0 }}>{k}</span>
                    <span style={{ color: 'var(--text-mid)', fontWeight: 500 }}>{v}</span>
                  </div>
                ))}
              </div>

              {/* Interview Rounds */}
              {loadingRounds && (
                <div style={{ textAlign: 'center', padding: '20px', color: 'var(--gray-400)' }}>
                  Loading rounds...
                </div>
              )}
              {roundsData && roundsData.rounds && roundsData.rounds.length > 0 && (
                <div>
                  <div style={{ fontWeight: 600, fontSize: 13, color: 'var(--text)', marginBottom: 12 }}>
                    Interview Rounds ({roundsData.rounds.length})
                  </div>
                  <div style={{ display: 'flex', flexDirection: 'column', gap: 10 }}>
                    {roundsData.rounds.map((round, idx) => (
                      <div key={round.id} style={{
                        padding: 12, background: 'var(--gray-50)', borderRadius: 6,
                        border: '1px solid var(--gray-200)', fontSize: 12
                      }}>
                        <div style={{ fontWeight: 600, marginBottom: 6, color: 'var(--text)' }}>
                          Round {round.roundNumber}: {round.roundType}
                        </div>
                        <div style={{ color: 'var(--gray-500)', marginBottom: 4 }}>
                          📅 {round.scheduledDate} | ⏰ {round.scheduledTime}
                        </div>
                        <div style={{ color: 'var(--gray-500)', marginBottom: 8 }}>
                          {round.interviewMode && `📱 ${round.interviewMode}`}
                          {round.location && ` | 📍 ${round.location}`}
                        </div>
                        <div style={{
                          display: 'inline-block', padding: '3px 8px', borderRadius: 3,
                          fontSize: 11, fontWeight: 600,
                          background: round.status === 'COMPLETED' ? 'var(--success)' : round.status === 'SCHEDULED' ? 'var(--warning)' : 'var(--gray-300)',
                          color: 'white', marginBottom: 6
                        }}>
                          {round.status}
                        </div>
                        {round.status === 'COMPLETED' && (
                          <div style={{ marginTop: 8, paddingTop: 8, borderTop: '1px solid var(--gray-200)' }}>
                            <div><strong>Result:</strong> {round.result === 'PASS' ? '✅ ' : '❌ '}{round.result}</div>
                            {round.score != null && <div><strong>Score:</strong> {round.score}</div>}
                            {round.feedback && <div style={{ marginTop: 4, color: 'var(--gray-600)', fontStyle: 'italic' }}>{round.feedback}</div>}
                          </div>
                        )}
                      </div>
                    ))}
                  </div>
                </div>
              )}
            </div>
          )}
        </div>
      </div>
    </>
  );
}
